{
  "title": "S3 लाइफसाइक्ल मैनेजमेंट",
  "group": "S3 लाइफसाइक्ल",
  "options": [
    {
      "text": "हाथ से ऑब्जेक्ट्स को बदलना"
    },
    {
      "text": "स्टोरेज क्लास में ऑब्जेक्ट्स को स्वतः बदलना"
    },
    {
      "text": "पुराने ऑब्जेक्ट्स को कभी नहीं हटाना"
    },
    {
      "text": "सबकुछ स्टैंडर्ड क्लास में स्टोर करना"
    }
  ],
  "questionProse": [
    "S3 लाइफसाइक्ल मैनेजमेंट क्या सक्षम बनाता है?"
  ],
  "explanationProse": [
    "लाइफसाइक्ल मैनेजमेंट:\n    - स्टोरेज क्लास में ऑब्जेक्ट्स को स्वतः बदलना\n    - कम उपयोग करने वाले डेटा को सस्ते स्टोरेज में शिफ्ट करना\n    - ऑब्जेक्ट्स के अवधि समाप्त होने के नियम लगाना\n    - स्टोरेज खरच कम करना\n    - मैन्युअल प्रबंधन के बोझ को कम करना\n\n    [S3 लाइफसाइक्ल नियम](https://docs.aws.amazon.com/AmazonS3/latest/userguide/lifecycle-configuration-examples.html)"
  ]
}
